UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg INNER JOIN `blog_article` a ON a.`id` = atg.`article_id` WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE t.`name` IN ('AI Agent', '人工智能', '大模型', '智能体', 'AI');
UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE c.`id` = 9600001;
UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE t.`id` = 9700001;
